use std::collections::{HashMap, VecDeque};

fn solve(n: i64, edges: Vec<Vec<i64>>) -> i64 {
    let mut graph: HashMap<i64, Vec<(i64, i64, i64)>> = HashMap::new();
    for edge in edges {
        let u = edge[0];
        let v = edge[1];
        let start = edge[2];
        let end = edge[3];
        graph.entry(u).or_insert_with(Vec::new).push((v, start, end));
    }

    let mut dist = HashMap::new();
    dist.insert(0, 0);
    let mut queue = VecDeque::new();
    queue.push_back(0);

    while let Some(node) = queue.pop_front() {
        let time = *dist.get(&node).unwrap();
        if node == n - 1 {
            continue;
        }

        // Try to stay at the current node
        if !dist.contains_key(&node) {
            dist.insert(node, time);
        }

        // Try to take each outgoing edge
        if let Some(edges) = graph.get(&node) {
            for &(v, start, end) in edges {
                if start <= time && time <= end {
                    let new_time = time + 1;
                    if !dist.contains_key(&v) || new_time < *dist.get(&v).unwrap() {
                        dist.insert(v, new_time);
                        queue.push_back(v);
                    }
                }
            }
        }
    }

    match dist.get(&(n - 1)) {
        Some(&time) => time,
        None => -1,
    }
}
